import{_ as a,o,c,a3 as d}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Module config:validate","description":"config:validate 模块负责对 Clore 配置值执行校验，确保其符合预定义的约束（如非零、非空、有效范围等）。模块公开了一个 ValidationError 结构体用于表示验证错误的信息，以及一个 validate 函数作为验证的入口点。该函数接受一个 const int & 类型的配置值，返回一个 int 结果：返回 0 表示验证通过，非零值对应特定错误码或失败原因。内部通过两个匿名命名空间中的辅助函数 validate_nonzero 和 validate_nonempty 实现具体的校验逻辑，但它们对外部是不可见的。该模块与 config:schema 等模块协作，形成完整的配置处理流水线，保证最终使用的配置合法可靠。","frontmatter":{"title":"Module config:validate","description":"config:validate 模块负责对 Clore 配置值执行校验，确保其符合预定义的约束（如非零、非空、有效范围等）。模块公开了一个 ValidationError 结构体用于表示验证错误的信息，以及一个 validate 函数作为验证的入口点。该函数接受一个 const int & 类型的配置值，返回一个 int 结果：返回 0 表示验证通过，非零值对应特定错误码或失败原因。内部通过两个匿名命名空间中的辅助函数 validate_nonzero 和 validate_nonempty 实现具体的校验逻辑，但它们对外部是不可见的。该模块与 config:schema 等模块协作，形成完整的配置处理流水线，保证最终使用的配置合法可靠。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/config/validate.md","filePath":"zh/clore/modules/config/validate.md"}'),i={name:"zh/clore/modules/config/validate.md"};function t(r,e,l,n,s,m){return o(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="module-config-validate" tabindex="-1">Module <code>config:validate</code> <a class="header-anchor" href="#module-config-validate" aria-label="Permalink to &quot;Module `config:validate`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>config:validate</code> 模块负责对 Clore 配置值执行校验，确保其符合预定义的约束（如非零、非空、有效范围等）。模块公开了一个 <code>ValidationError</code> 结构体用于表示验证错误的信息，以及一个 <code>validate</code> 函数作为验证的入口点。该函数接受一个 <code>const int &amp;</code> 类型的配置值，返回一个 <code>int</code> 结果：返回 <code>0</code> 表示验证通过，非零值对应特定错误码或失败原因。内部通过两个匿名命名空间中的辅助函数 <code>validate_nonzero</code> 和 <code>validate_nonempty</code> 实现具体的校验逻辑，但它们对外部是不可见的。该模块与 <code>config:schema</code> 等模块协作，形成完整的配置处理流水线，保证最终使用的配置合法可靠。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./schema"><code>config:schema</code></a></li><li><code>std</code></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-config-validationerror" tabindex="-1"><code>clore::config::ValidationError</code> <a class="header-anchor" href="#clore-config-validationerror" aria-label="Permalink to &quot;`clore::config::ValidationError`&quot;">​</a></h3><p>Declaration: <code>config/validate.cppm:8</code></p><p>Definition: <code>config/validate.cppm:8</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>结构体 <code>clore::config::ValidationError</code> 只包含一个公开数据成员 <code>std::string message</code>，没有用户定义的构造函数、析构函数或赋值运算符，因此作为平凡可复制类型适合按值传递。其内部不变量是 <code>message</code> 必须持有描述验证失败的文本内容，但不对字符串长度或格式施加任何额外约束；所有错误信息完全由该字符串承载，且结构体本身不执行任何验证、转换或剪裁逻辑。由于 <code>clore::config::ValidationError</code> 的状态完全由 <code>message</code> 决定，其实现极为简单，仅作为错误文本的轻量容器。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>无额外不变量，结构体仅作为错误消息的容器。</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>std::string message</code>：存储验证错误消息。</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>被验证函数返回或赋值以报告错误。</li><li>作为错误集合的一部分被收集和检查。</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-config-validate" tabindex="-1"><code>clore::config::validate</code> <a class="header-anchor" href="#clore-config-validate" aria-label="Permalink to &quot;`clore::config::validate`&quot;">​</a></h3><p>Declaration: <code>config/validate.cppm:12</code></p><p>Definition: <code>config/validate.cppm:42</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>该函数通过一系列顺序检查对传入的 <code>TaskConfig</code> 对象执行基于规则的验证。首先依次验证 <code>compile_commands_path</code>、<code>project_root</code>、<code>output_root</code> 三个路径字段：使用 <code>std::filesystem::exists</code> 检查路径是否存在、使用 <code>is_regular_file</code> 或 <code>is_directory</code> 确认文件类型符合预期，若失败则返回包含相应错误消息的 <code>std::unexpected</code>（消息由 <code>std::format</code> 构造）。随后对 LLM 配置子对象调用同匿名命名空间中的 <code>validate_nonempty</code> 检查 <code>llm.system_prompt</code> 非空，调用 <code>validate_nonzero</code> 确保 <code>llm.retry_limit</code> 为非零值。所有检查均返回 <code>std::expected&lt;void, clore::config::ValidationError&gt;</code>，一旦任何验证项失败立即短路返回，全部通过则返回 <code>{}</code>。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>config<code>.compile_commands_path</code></li><li>config<code>.project_root</code></li><li>config<code>.output_root</code></li><li>config<code>.llm``.system_prompt</code></li><li>config<code>.llm``.retry_limit</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>validate a loaded <code>TaskConfig</code> before use</li><li>called after <code>load_config</code> or <code>load_config_from_string</code></li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>模块 <code>config:validate</code> 主要负责对配置值执行约束检查，其公开入口为函数 <code>clore::config::validate</code>。为支持复用和清晰分离，模块内部在匿名命名空间中拆解了 <code>validate_nonzero</code> 和 <code>validate_nonempty</code> 两个辅助函数，它们分别针对不同的验证规则（如非零、非空）。验证错误通过公开结构体 <code>ValidationError</code>（包含字符串字段 <code>message</code>）进行传递。模块导入依赖 <code>config:schema</code> 以获取配置类型定义，并直接依赖 <code>std</code> 作为底层基础设施。整体实现结构遵循“公开接口 + 内部工具函数”的简单分层，验证逻辑集中在匿名命名空间内，避免了外部可见的辅助符号。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./schema">Module config:schema</a></li></ul>',33)])])}const u=a(i,[["render",t]]);export{h as __pageData,u as default};
